## Output Comparison Tests

```rust
/// Test exact log output matches Go
#[test]
fn test_info_log_format() {
    let mut buffer = Vec::new();
    let logger = Logger::new().with_output(&mut buffer);

    logger.info("Server started", "port", 8080, "host", "localhost");

    let output = String::from_utf8(buffer).unwrap();

    ctx.log_expected("output", GO_FIXTURES.log_info_server_started);
    ctx.log_actual("output", &output);

    // Compare ANSI-normalized
    assert_ansi_eq(&output, GO_FIXTURES.log_info_server_started);
}

/// Test structured fields
#[test]
fn test_with_fields() {
    let logger = Logger::new()
        .with("request_id", "abc123")
        .with("user_id", 42);

    let mut buffer = Vec::new();
    logger.with_output(&mut buffer).info("Processing");

    let output = String::from_utf8(buffer).unwrap();

    // Verify fields appear in output
    assert!(output.contains("request_id"));
    assert!(output.contains("abc123"));
    assert!(output.contains("user_id"));
    assert!(output.contains("42"));
}
```

