+impl StyleState {
+    fn to_span(&self, text: String) -> StyledSpan {
+        StyledSpan {
+            text,
+            bold: self.bold,
+            italic: self.italic,
+            underline: self.underline,
+            strikethrough: self.strikethrough,
+            faint: self.faint,
+            foreground: self.foreground.clone(),
+            background: self.background.clone(),
+        }
