+    fn apply_sgr(&mut self, params: &[u32]) {
+        let mut i = 0;
+        while i < params.len() {
+            match params[i] {
+                0 => self.reset(),
+                1 => self.bold = true,
+                2 => self.faint = true,
+                3 => self.italic = true,
+                4 => self.underline = true,
+                9 => self.strikethrough = true,
+                22 => {
+                    self.bold = false;
+                    self.faint = false;
+                }
+                23 => self.italic = false,
+                24 => self.underline = false,
+                29 => self.strikethrough = false,
+                // Standard foreground colors (30-37)
+                30..=37 => self.foreground = Some(params[i].to_string()),
+                39 => self.foreground = None, // Default foreground
+                // Standard background colors (40-47)
+                40..=47 => self.background = Some(params[i].to_string()),
+                49 => self.background = None, // Default background
+                // Extended colors (38;5;n or 38;2;r;g;b)
+                38 => {
+                    if i + 1 < params.len() {
+                        match params[i + 1] {
+                            5 => {
+                                // 256 color
+                                if i + 2 < params.len() {
+                                    self.foreground =
+                                        Some(format!("38;5;{}", params[i + 2]));
+                                    i += 2;
+                                }
+                            }
+                            2 => {
+                                // True color
+                                if i + 4 < params.len() {
+                                    self.foreground = Some(format!(
+                                        "38;2;{};{};{}",
+                                        params[i + 2],
+                                        params[i + 3],
+                                        params[i + 4]
+                                    ));
+                                    i += 4;
+                                }
+                            }
+                            _ => {}
+                        }
+                    }
+                }
+                // Extended background colors
+                48 => {
+                    if i + 1 < params.len() {
+                        match params[i + 1] {
+                            5 => {
+                                if i + 2 < params.len() {
+                                    self.background =
+                                        Some(format!("48;5;{}", params[i + 2]));
+                                    i += 2;
+                                }
+                            }
+                            2 => {
+                                if i + 4 < params.len() {
+                                    self.background = Some(format!(
+                                        "48;2;{};{};{}",
+                                        params[i + 2],
+                                        params[i + 3],
+                                        params[i + 4]
+                                    ));
+                                    i += 4;
+                                }
+                            }
+                            _ => {}
+                        }
+                    }
+                }
+                // Bright foreground colors (90-97)
+                90..=97 => self.foreground = Some(params[i].to_string()),
+                // Bright background colors (100-107)
+                100..=107 => self.background = Some(params[i].to_string()),
+                _ => {}
+            }
+            i += 1;
+        }
+    }
+}
